mapper.select:
SELECT 
FROM securities_executions
WHERE member_id = #{memberId}
ORDER BY executed_at DESC, id DESC
LIMIT #{limit}

SELECT COALESCE(SUM(realized_profit), 0)
FROM securities_executions
WHERE member_id = #{memberId}
  AND execution_side = 'SELL'
  AND executed_at >= #{from}
  AND executed_at < #{to}
